import React, { useEffect, useState } from "react";
import "./nhanvien.css";
import { fetchWithAuth } from "../../helper/fetchWithAuth";


function Nhanvien() {
  const [customers, setCustomers] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [newusers, setNewusers] = useState({
    id: "",
    name: "",
    role: "",
    phonenumber: "",
    email: "",
    address: "",
    salary: "",
    salarybonus: "",
    defaultsalary: "",
    carsoldtotal: "",
  });
  
  const [editMode, setEditMode] = useState(false); // Chế độ chỉnh sửa
  const [editUser, setEditUser] = useState(null); // Khách hàng đang chỉnh sửa
  const [openmodal, setmodal] = useState(false);

  const fetchEmployees = async () => {
    try {
      const response = await fetchWithAuth("/api/employees");
      const data = await response.json();
      setVehicles(data);
    } catch (error) {
      console.error("Lỗi khi lấy dữ liệu xe:", error);
    }
  };

  if (loading) return <p>Loading...</p>;
  // if (error) return (alert('Bạn cần phải đăng nhập'));

  return (
    <div className="customer-table">
      <h2>Bảng Nhân Viên</h2>
      <button onClick={handleOpen} style={{ cursor: "pointer" }}>
        + Nhân viên mới
      </button>
      {openmodal && (
        <form
          onSubmit={editMode ? handleUpdateUser: handleAddUser}
          className="add-customer-form"
        >
          <div className="add-customer-form--body">
            <input
              type="text"
              name="name"
              placeholder="Tên nhân viên"
              value={newusers.name}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="username"
              placeholder="Tên đăng nhập"
              value={newusers.username}
              onChange={handleInputChange}
              required
            />
            <input
              type="password"
              name="password"
              placeholder="Mật khẩu"
              value={newusers.password}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="role"
              placeholder="Chức vụ"
              value={newusers.role}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="phonenumber"
              placeholder="Số điện thoại"
              value={newusers.phonenumber}
              onChange={handleInputChange}
              required
            />
            <input
              type="email"
              name="email"
              placeholder="Email"
              value={newusers.email}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="address"
              placeholder="Địa chỉ"
              value={newusers.address}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="salary"
              placeholder="Lương"
              value={newusers.salary}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="salarybonus"
              placeholder="Lương thưởng"
              value={newusers.salarybonus}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="defaultsalary"
              placeholder="Lương mặc định"
              value={newusers.defaultsalary}
              onChange={handleInputChange}
              required
            />
            <input
              type="text"
              name="carsoldtotal"
              placeholder="Số xe bán được"
              value={newusers.carsoldtotal}
              onChange={handleInputChange}
              required
            />
            <div className="group-btn">
              <button type="submit">{editMode ? "Cập nhật" : "Thêm"}</button>
            </div>
          </div>
        </form>
      )}

      <table>
        <thead>
          <tr>
            <th>Tên nhân viên</th>
            <th>Chức vụ</th>
            <th>SDT</th>
            <th>Email</th>
            <th>Địa chỉ</th>
            <th>Lương</th>
            <th>Lương thưởng</th>
            <th>Lương mặc định</th>
            <th>Số xe bán được</th>
            <th>Thay đổi</th>
          </tr>
        </thead>
        <tbody>
          {customers.map((user) => (
            <tr key={user.id}>
              <td>{user.name}</td>
              <td>{user.role}</td>
              <td>{user.phonenumber}</td>
              <td>{user.email}</td>
              <td>{user.address}</td>
              <td>{user.salary}</td>
              <td>{user.salarybonus}</td>
              <td>{user.defaultsalary}</td>
              <td>{user.carsoldtotal}</td>

              <td>
                <button onClick={() => handleEdit(user)}>Sửa</button>
                <button onClick={() => handleDelete(user.id)}>Xóa</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default Nhanvien;
